# Problem parameters
workers = ['I', 'II', 'III', 'IV', 'V']
tasks = ['A', 'B', 'C', 'D']
worker_tasks_hours = {
    'I': [9, 4, 3, 7],
    'II': [4, 6, 5, 6],
    'III': [5, 4, 7, 5],
    'IV': [7, 5, 2, 3],
    'V': [10, 6, 7, 4]
}

# Objective function
def objective(x):
    return np.sum([worker_tasks_hours[workers[i]][tasks.index(task)] * x[i] for i in range(len(workers))])

# Constraint functions
def constraint1(x):
    return np.sum(x) - 4

def constraint2(x):
    return [np.sum([x[i] if workers[i] == task else 0 for i in range(len(workers))]) - 1 for task in tasks]

# Hyper-heuristic operators
class GreedyOperator:
    def __init__(self, x):
        self.x = x

    def apply(self):
        best_worker = None
        best_task = None
        best_improvement = float('inf')
        for worker in workers:
            for task in tasks:
                if not any([i == j and w == worker and t == task for i, (j, w) in enumerate(zip(range(len(workers)), workers))]):
                    new_x = self.x.copy()
                    new_x[workers.index(worker)] = 1
                    new_x[tasks.index(task)] = 1
                    improvement = objective(new_x) - self.x.sum()
                    if improvement < best_improvement:
                        best_worker = worker
                        best_task = task
                        best_improvement = improvement
        return best_worker, best_task

class LocalSearchOperator:
    def __init__(self, x):
        self.x = x

    def apply(self):
        best_x = self.x.copy()
        best_fitness = objective(best_x)
        for worker in workers:
            for task in tasks:
                new_x = best_x.copy()
                new_x[workers.index(worker)] = 0
                new_x[tasks.index(task)] = 1
                fitness = objective(new_x)
                if fitness < best_fitness:
                    best_x = new_x
                    best_fitness = fitness
        return best_x

class CrossoverOperator:
    def __init__(self, x):
        self.x = x

    def apply(self):
        parent1 = np.random.choice(len(workers), 2, replace=False)
        parent2 = [i for i in range(len(workers)) if i not in parent1]
        child = []
        for i in sorted(parent1):
            child.append(self.x[i])
        for task in tasks:
            if self.x[workers.index(task)] == 0:
                child.append(1)
            else:
                child.append(0)
        return child

class SelectionHyperHeuristic:
    def __init__(self, x, operators):
        self.x = x
        self.operators = operators
        self.performance_weights = [0] * len(operators)

    def choose_operator(self):
        total_performance = sum([performance for _, performance in zip(self.operators, [objective(self.operator.apply()) if isinstance(self.operator, GreedyOperator) else 1 for self.operator in self.operators])])
        for i, operator in enumerate(self.operators):
            if isinstance(operator, GreedyOperator):
                self.performance_weights[i] = (performance / total_performance) ** 0.5
            elif isinstance(operator, LocalSearchOperator):
                self.performance_weights[i] = performance ** 0.5
            else:
                self.performance_weights[i] = 1
        return np.random.choice(len(self.operators), p=[weight for weight in self.performance_weights])

    def run(self, iterations):
        x_best = self.x.copy()
        best_fitness = objective(x_best)
        for _ in range(iterations):
            operator_index = self.choose_operator()
            self.x = self.operators[operator_index].apply()
            fitness = objective(self.x)
            if fitness < best_fitness:
                best_fitness = fitness
                x_best = self.x.copy()
        return x_best

